import { useDispatch, useSelector } from 'react-redux';
import { addToCart, removeFromCart, updateQuantity, clearCart } from '../redux/cartSlice';

export const useCart = () => {
  const dispatch = useDispatch();

  // ========================================================
  // CRITICAL FIX: LIVE REDUX SUBSCRIPTION
  // By using useSelector, any component using this hook will 
  // instantly re-render the millisecond the Redux state changes.
  // ========================================================
  const items = useSelector((state) => state.cart?.items) || [];

  const addItem = (product, variant, quantity = 1) => {
    dispatch(addToCart({ product, variant, quantity }));
  };

  const removeItem = (productId, variantId) => {
    dispatch(removeFromCart({ productId, variantId }));
  };

  const changeQuantity = (productId, variantId, quantity) => {
    dispatch(updateQuantity({ productId, variantId, quantity }));
  };

  const emptyCart = () => {
    dispatch(clearCart());
  };

  const getCartTotal = () => {
    return items.reduce((total, item) => {
      const price = Number(item.price) || 0;
      const qty = Number(item.quantity) || 1;
      return total + (price * qty);
    }, 0);
  };

  return {
    items,
    addItem,
    removeItem,
    changeQuantity,
    emptyCart,
    getCartTotal,
  };
};
